14	const DESCRIPTIONS = [
15	  "Grocery store purchase",
16	  "Monthly subscription",
17	  "Online order",
18	  "Restaurant dinner",
19	  "Gas station",
20	  "Pharmacy",
21	  "Coffee shop",
22	  "Movie tickets",
23	  "Bus pass",
24	  "Electric bill",
25	  "Water bill",
26	  "Book purchase",
27	  "Gym membership",
28	  "Flight booking",
29	  "Hotel stay",
30	  "Taxi ride",
31	  "Concert tickets",
32	  "Clothing store",
33	  "Hardware store",
34	  "Insurance premium",
35	];
