    if (existing) {
      existing.transactions.push(t);
    } else {
      map.set(key, { key, transactions: [t] });
    }
  }

  // Only return groups that actually have duplicates (>1 transaction)
  return Array.from(map.values()).filter((g) => g.transactions.length > 1);
}
```

### Step 3 — `calculateRunningBalance`

Replace the O(n × m) loop with three clean passes:

```ts
export function calculateRunningBalance(
  transactions: Transaction[],
  userId: string
): RunningBalanceEntry[] {
  // Single filter pass
  const userTransactions = transactions.filter((t) => t.userId === userId);

  // Sort once
  userTransactions.sort((a, b) => a.date.localeCompare(b.date));

  // Single accumulation pass — keep running sum unrounded to match original FP behaviour
  const entries: RunningBalanceEntry[] = [];
  let runningSum = 0;
  for (const t of userTransactions) {
    runningSum += t.amount;
    entries.push({
      transactionId: t.id,
      amount: t.amount,
      balance: Math.round(runningSum * 100) / 100,
      date: t.date,
    });
  }

  return entries;
}
```

### Step 4 — `topSpenders`

Replace `includes` + per-user rescan + bubble sort:

```ts
export function topSpenders(
  transactions: Transaction[],
  n: number
): SpenderSummary[] {
  const map = new Map<string, { total: number; count: number }>();

  for (const t of transactions) {
    const existing = map.get(t.userId);
    if (existing) {
      existing.total += t.amount;
      existing.count++;
    } else {
      map.set(t.userId, { total: t.amount, count: 1 });
    }
  }

  const summaries: SpenderSummary[] = Array.from(map.entries()).map(
    ([userId, { total, count }]) => ({
      userId,
      totalSpent: Math.round(total * 100) / 100,
      transactionCount: count,
    })
  );

  summaries.sort((a, b) => b.totalSpent - a.totalSpent);

  return summaries.slice(0, n);
}
```

### Step 5 — `searchTransactions`

Hoist RegExp creation; replace linear dedup with Set:

```ts
export function searchTransactions(
  transactions: Transaction[],
  query: string
): Transaction[] {
  // Compile once outside the loop
  const pattern = new RegExp(
    query.replace(/[.*+?^${}()|[\]\\]/g, "\\$&"),
    "i"
  );

  const seen = new Set<string>();
  const results: Transaction[] = [];

  for (const t of transactions) {
    if (pattern.test(t.description) && !seen.has(t.id)) {
      seen.add(t.id);
      results.push(t);
    }
  }

  return results;
}
```

### Step 6 — `processAll`

No changes required. It already delegates to the individual functions.

